import React from 'react';

const ProductionScore = ({ data }: { data: any }) => {
    if (!data) return null;

    const score = data.readiness_score;
    const isGreen = data.status === "GREEN";

    return (
        <div className="bg-gray-800 rounded-xl p-6 border border-gray-700 shadow-lg h-full flex flex-col justify-center items-center relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4">
                <span className="px-3 py-1 text-xs font-semibold uppercase tracking-wider text-gray-400 bg-gray-900 rounded-full border border-gray-700">
                    Agent 7
                </span>
            </div>

            <h3 className="text-gray-400 font-medium text-sm uppercase tracking-widest mb-6">Production Readiness</h3>

            <div className="relative flex items-center justify-center w-48 h-48">
                {/* SVG Gauge Implementation */}
                <svg className="w-full h-full transform -rotate-90" viewBox="0 0 100 100">
                    <circle cx="50" cy="50" r="45" fill="none" stroke="#374151" strokeWidth="8" />
                    <circle
                        cx="50" cy="50" r="45"
                        fill="none"
                        stroke={isGreen ? "#10b981" : "#ef4444"}
                        strokeWidth="8"
                        strokeDasharray={`${(score / 100) * 283} 283`}
                        className="transition-all duration-1000 ease-out"
                    />
                </svg>
                <div className="absolute flex flex-col items-center">
                    <span className="text-5xl font-black text-white">{score}</span>
                    <span className={`text-sm font-bold uppercase tracking-wider mt-1 ${isGreen ? 'text-emerald-400' : 'text-red-400'}`}>
                        {data.status}
                    </span>
                </div>
            </div>

            <p className="text-gray-400 text-sm mt-6 text-center px-4">
                Based on lifelines Actuarial CI/CD model. System exhibits 99% probability of 30-day survival.
            </p>
        </div>
    );
};

export default ProductionScore;
